#include <stdio.h>
#include <stdlib.h>
#include <assert.h>

void spiralmatValues(int mat[][100], int n, int m) {
    int left = 0, right = m - 1, bottom = n - 1, top = 0;
    int direction = 1;

    while (left <= right && top <= bottom) {
        if (direction == 1) {
            for (int i = left; i <= right; i++) 
                printf("%d ", mat[top][i]);
            direction = 2;
            top++;
        } else if (direction == 2) {
            for (int i = top; i <= bottom; i++) 
                printf("%d ", mat[i][right]);
            direction = 3;
            right--;
        } else if (direction == 3) {
            for (int i = right; i >= left; i--) 
                printf("%d ", mat[bottom][i]);
            direction = 4;
            bottom--;
        } else if (direction == 4) {
            for (int i = bottom; i >= top; i--) 
                printf("%d ", mat[i][left]);
            direction = 1;
            left++;
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);

        assert(1 <= n && n <= 100);
        assert(1 <= m && m <= 100);

        int mat[100][100];

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                scanf("%d", &mat[i][j]);
            }
        }

        spiralmatValues(mat, n, m);
        printf("\n");
    }
    return 0;
}

